    buildTaskMap: function(widgetId, map, gr, fields) {
        //var taskO = this.getTaskTreeLevelO(gr);
        var taskO = this.getTaskListTreeLevelO(gr, fields, 1, widgetId);
        // the top node of the tree cannot have a parent
        delete taskO.parent;

        map.push(taskO);
        this.getTasks(widgetId,fields, taskO.level, map, taskO, taskO.sys_id);
    },

	// this is a recursive function used to load all tasks in the task tree into the Data for widgets
	getTasks: function(widgetId, fields, level, map, taskO, sys_id) {
		var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
		grTask.addQuery('parent', sys_id);
		grTask.orderBy('order');
		grTask.orderBy('number');
		grTask.query();
		var parentAfterAllChildren = true;
		while (grTask.next()) {
			if (!grTask.canRead()) {
				continue;
			}
			var taskLevelO = this.getTaskListTreeLevelO(grTask, fields, level, widgetId);
			map.push(taskLevelO);
			this.getTasks(widgetId, fields, level + 1, map, taskLevelO, grTask.getUniqueValue());
			if (widgetId == 'discovertasker-recursivetasktreegraph') {
				if (taskLevelO.suspense_date > taskO.suspense_date) {
					parentAfterAllChildren = false;
					taskLevelO.warning.isSuspenseDateAfterParent = true;
				}
			}
		}
		if (widgetId == 'discovertasker-recursivetasktreegraph') {
			// STRY0095748 - no suspensedate warning
			taskO.warning.noSuspenseDate = (taskO.suspense_date == '' || taskO.suspense_date == null);
			taskO.warning.waitStatewithNoSubtasks = (taskO.u_wait_for_subtasks_to_finish && (taskO.calchaschildren == 0));
			taskO.warning.isSuspenseDateAfterChildren = parentAfterAllChildren;
			taskO.warning.primaryAssigneeEmpty = (taskO.primary_assignee == '' || taskO.primary_assignee == null);
			taskO.warning.assignedMemberEmpty = (taskO.assigned_to == '' || taskO.assigned_to == null);
		}
	},

    getTaskListTreeLevelO: function(record, fields, level, widgetId) {
        var displayValue = '';
        var newNodeData = {};
        var sys_id = record.getUniqueValue();
        newNodeData.key = sys_id;
        newNodeData.sys_id = sys_id;
        newNodeData.level = level;
        for (var key in fields) {
            var field = fields[key];
            displayValue = record.getDisplayValue(key) + '';

            if (field.maxChars > 0)
                displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
            var fieldLabel = '';
            fieldLabel = field.fieldLabel;
            if (field.keyUsesDisplayOnly) {
                newNodeData[key] = displayValue;
            }
            if (field.hasValue) {
                newNodeData[key] = record.getValue(key);
            }
            if (field.hasDiplayValue) {
                newNodeData[key + '_DisplayValue'] = displayValue;
            }
            if (field.type == 'date') {
                var date_number = record[key].dateNumericValue();
                newNodeData[key] = date_number;
            }
            if (field.type == 'boolean') {
                var boolean_value = record[key] == 1;
                newNodeData[key] = boolean_value;
            }
        }

        // These are the custom fields in this data set, compare with other data sets and determine best way to bring together.
        if (widgetId == 'discovertasker-recursivetasktreelist') {
            newNodeData.text = this.getTaskTreeListTitleNode(newNodeData, newNodeData.parent, newNodeData.task_name, newNodeData.primary_assignee, newNodeData.assigned_to, newNodeData.state, newNodeData.order);
            // we will expand all on initial page load
            newNodeData.expanded = true;
            // NOTE you are here, there is an issue with leaf nodes having the down chevron when they should not	
            // this should be removed
            newNodeData.href = '/discovertaskerportal?id=discovertasker_taskdetails&sys_id=' + newNodeData.sys_id + '&table=x_153465_discovert_route_task_instance&view=sp' + '&state=' + newNodeData['state'] + '&order=' + newNodeData['order'];
        }
        // Load the name value for the Task Tree Graph
        if (widgetId == 'discovertasker-recursivetasktreegraph') {
            newNodeData.name = this.getTaskTitleNode(record);
			newNodeData.warning = {};
			newNodeData.isInboundExternalOU = !record.parent && record.tasking_authority && (record.tasking_authority.u_external_flag == true);
			newNodeData.warning.isTopSuspenseDateAfterExternalInboundDate = newNodeData.isInboundExternalOU && (record.suspense_date > record.u_external_due_date);
			newNodeData.isOutboundExternalOU = (record.outbound == true);
			newNodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate = newNodeData.isOutboundExternalOU && (record.u_external_due_date > record.suspense_date);
        }
        return newNodeData;
    },
    //------------------------------------------------------------------------------------------------------------------------
    // GET TASK TITLE
    //------------------------------------------------------------------------------------------------------------------------
    getTaskTreeListTitleNode: function(newNodeData, parent, TaskNameNumber, Primary_Assignee, Assigned_To, State, Order) {
        var taskText = {};
        if (parent != null) TaskNameNumber = Order + ". " + TaskNameNumber; // NEW
        newNodeData.TaskNameNumber = TaskNameNumber;
        taskText = {
            TaskNameNumber: TaskNameNumber,
            primary_assignee: Primary_Assignee,
            assigned_to: Assigned_To,
            State: State,
            Order: Order
        };
        if (Assigned_To != '')
            taskText.assigned_to = '(' + Assigned_To + ')';

        var badgeclass = "label label-" + State;
        taskText.state = State;
        return taskText;
    },
    //------------------------------------------------------------------------------------------------------------------------
    // SEQ - Task Details page – Displays Task Tree View Indicators 
    //------------------------------------------------------------------------------------------------------------------------
    getTaskTitleNode: function(grTask) {
        var nodeTitle = grTask.task_name.toString();
        if (grTask.parent != '') nodeTitle = grTask.order.toString() + ". " + nodeTitle; // NEW

        // 2.5.13: 08.12.20 | KT | SEQ | STRY0076601: SEQ - Task Details page – Displays Task Tree View Indicators 
        //if (grTask.assigned_to.getDisplayValue().toString().length > 0) nodeTitle += " (" + grTask.assigned_to.getDisplayValue().toString() + ") "; //KT: 06.09.20: Added space before (Assignee
        switch (grTask.state.getDisplayValue().toString()) {
            case 'Waiting':
                if (grTask.calchaschildren.getDisplayValue().toString() == '0'
                    //grTask.u_active_subtasks.getDisplayValue().toString() == grTask.calchaschildren.getDisplayValue().toString() && 
                )
                    nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " on creating Subtasks ";
                else
                    nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " on " + grTask.u_active_subtasks.getDisplayValue().toString() + " out of " + grTask.calchaschildren.getDisplayValue().toString() + " Subtasks";
                break;
            case 'Assigned':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " to " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Accepted':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Work in Progress':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'In Review':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " by " + grTask.u_reviewer.getDisplayValue().toString() + ", Worked by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Completed':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            default:
                nodeTitle += " - " + grTask.state.getDisplayValue().toString();
                break;
        }
        return nodeTitle;
        //------------------------------------------------------------------------------------------------------------------------
    },

    type: 'TaskWidgetData'
};
